+import Adw from 'gi://Adw';
+import Gio from 'gi://Gio';
+import Gtk from 'gi://Gtk';
+import {ExtensionPreferences} from 'resource:///org/gnome/Shell/Extensions/js/extensions/prefs.js';
+
+export default class MutterButterPreferences extends ExtensionPreferences {
+    fillPreferencesWindow(window) {
+        const settings = this.getSettings();
+
+        // --- Grid page ---
+        const gridPage = new Adw.PreferencesPage({title: 'Grid', icon_name: 'view-grid-symbolic'});
+        window.add(gridPage);
+
+        const gridGroup = new Adw.PreferencesGroup({title: 'Grid Configuration'});
+        gridPage.add(gridGroup);
+
+        // Monitor selector
+        const connectors = settings.get_strv('monitor-connectors');
+        if (connectors.length === 0) {
+            const noMonRow = new Adw.ActionRow({
+                title: 'No monitors detected',
+                subtitle: 'Enable the extension first, then reopen preferences',
+            });
+            gridGroup.add(noMonRow);
+        } else {
+            const monitorModel = new Gtk.StringList();
+            for (const c of connectors)
+                monitorModel.append(c);
+
+            const monitorRow = new Adw.ComboRow({
+                title: 'Monitor',
+                model: monitorModel,
+            });
+            gridGroup.add(monitorRow);
+
+            const colsRow = new Adw.SpinRow({
+                title: 'Columns',
+                adjustment: new Gtk.Adjustment({lower: 4, upper: 32, step_increment: 1, value: 8}),
+            });
+            gridGroup.add(colsRow);
+
+            const rowsRow = new Adw.SpinRow({
+                title: 'Rows',
+                adjustment: new Gtk.Adjustment({lower: 3, upper: 24, step_increment: 1, value: 6}),
+            });
+            gridGroup.add(rowsRow);
+
+            // Bind to per-monitor settings.
+            // Track signal IDs to disconnect on monitor switch (prevents leaks).
+            let colsHandlerId = 0;
+            let rowsHandlerId = 0;
+            const updateMonitorSettings = () => {
+                // Disconnect old handlers
+                if (colsHandlerId)
+                    colsRow.adjustment.disconnect(colsHandlerId);
+                if (rowsHandlerId)
+                    rowsRow.adjustment.disconnect(rowsHandlerId);
+
+                const idx = monitorRow.get_selected();
+                const connector = connectors[idx];
+                if (!connector) return;
+                const sanitized = connector.replace(/[^a-zA-Z0-9-]/g, '_');
+                const path = `/org/gnome/shell/extensions/mutter-butter/monitor/${sanitized}/`;
+                const monSettings = new Gio.Settings({
+                    schema_id: 'org.gnome.shell.extensions.mutter-butter.monitor',
+                    path,
+                });
+                colsRow.adjustment.value = monSettings.get_int('grid-columns');
+                rowsRow.adjustment.value = monSettings.get_int('grid-rows');
+
+                colsHandlerId = colsRow.adjustment.connect('value-changed', () => {
+                    monSettings.set_int('grid-columns', colsRow.adjustment.value);
+                });
+                rowsHandlerId = rowsRow.adjustment.connect('value-changed', () => {
+                    monSettings.set_int('grid-rows', rowsRow.adjustment.value);
+                });
+            };
+            monitorRow.connect('notify::selected', updateMonitorSettings);
+            updateMonitorSettings();
+        }
+
+        // --- Behavior page ---
+        const behaviorPage = new Adw.PreferencesPage({title: 'Behavior', icon_name: 'preferences-system-symbolic'});
+        window.add(behaviorPage);
+
+        const behaviorGroup = new Adw.PreferencesGroup({title: 'Auto-Shrink Behavior'});
+        behaviorPage.add(behaviorGroup);
+
+        const thresholdRow = new Adw.SpinRow({
+            title: 'Focus Rank Threshold',
+            subtitle: 'Number of top-ranked windows that stay full size',
+            adjustment: new Gtk.Adjustment({lower: 1, upper: 20, step_increment: 1, value: 3}),
+        });
+        settings.bind('focus-rank-threshold', thresholdRow.adjustment, 'value',
+            Gio.SettingsBindFlags.DEFAULT);
+        behaviorGroup.add(thresholdRow);
+
+        const placementModel = new Gtk.StringList();
+        placementModel.append('In Place');
+        placementModel.append('Shelf');
+        placementModel.append('Pack');
+        const placementRow = new Adw.ComboRow({
+            title: 'Stamp Placement',
+            model: placementModel,
+        });
+        const modeMap = ['in-place', 'shelf', 'pack'];
+        placementRow.set_selected(modeMap.indexOf(settings.get_string('placement-mode')));
+        placementRow.connect('notify::selected', () => {
+            settings.set_string('placement-mode', modeMap[placementRow.get_selected()]);
+        });
+        behaviorGroup.add(placementRow);
+
+        const edgeModel = new Gtk.StringList();
+        edgeModel.append('Bottom');
+        edgeModel.append('Top');
+        edgeModel.append('Left');
+        edgeModel.append('Right');
+        const edgeRow = new Adw.ComboRow({
+            title: 'Shelf Edge',
+            model: edgeModel,
+        });
+        const edgeMap = ['bottom', 'top', 'left', 'right'];
+        edgeRow.set_selected(edgeMap.indexOf(settings.get_string('shelf-edge')));
+        edgeRow.connect('notify::selected', () => {
+            settings.set_string('shelf-edge', edgeMap[edgeRow.get_selected()]);
+        });
+        behaviorGroup.add(edgeRow);
+
+        const depthRow = new Adw.SpinRow({
+            title: 'Max Shelf Depth',
+            adjustment: new Gtk.Adjustment({lower: 1, upper: 4, step_increment: 1, value: 2}),
+        });
+        settings.bind('shelf-max-depth', depthRow.adjustment, 'value',
+            Gio.SettingsBindFlags.DEFAULT);
+        behaviorGroup.add(depthRow);
+
+        const hysteresisRow = new Adw.SpinRow({
+            title: 'Hysteresis (ms)',
+            subtitle: 'Cooldown before indirect restoration',
+            adjustment: new Gtk.Adjustment({lower: 0, upper: 10000, step_increment: 100, value: 2000}),
+        });
+        settings.bind('hysteresis-ms', hysteresisRow.adjustment, 'value',
+            Gio.SettingsBindFlags.DEFAULT);
+        behaviorGroup.add(hysteresisRow);
+
+        // --- Keybindings group ---
+        const keybindGroup = new Adw.PreferencesGroup({title: 'Keybindings'});
+        behaviorPage.add(keybindGroup);
+
+        const zoomInRow = new Adw.EntryRow({
+            title: 'Zoom In',
+            text: settings.get_strv('zoom-in-keybind')[0] || '<Super>KP_Add',
+        });
+        zoomInRow.connect('apply', () => {
+            settings.set_strv('zoom-in-keybind', [zoomInRow.get_text()]);
+        });
+        keybindGroup.add(zoomInRow);
+
+        const zoomOutRow = new Adw.EntryRow({
+            title: 'Zoom Out',
+            text: settings.get_strv('zoom-out-keybind')[0] || '<Super>KP_Subtract',
+        });
+        zoomOutRow.connect('apply', () => {
+            settings.set_strv('zoom-out-keybind', [zoomOutRow.get_text()]);
+        });
+        keybindGroup.add(zoomOutRow);
+
+        // --- Exempt Apps group ---
+        const exemptGroup = new Adw.PreferencesGroup({title: 'Exempt Applications'});
+        behaviorPage.add(exemptGroup);
+
+        const exemptApps = settings.get_strv('exempt-apps');
+        for (const appId of exemptApps) {
+            const row = new Adw.ActionRow({title: appId});
+            const removeBtn = new Gtk.Button({
+                icon_name: 'list-remove-symbolic',
+                valign: Gtk.Align.CENTER,
+            });
+            removeBtn.connect('clicked', () => {
+                const current = settings.get_strv('exempt-apps');
+                settings.set_strv('exempt-apps',
+                    current.filter(a => a !== appId));
+                exemptGroup.remove(row);
+            });
+            row.add_suffix(removeBtn);
+            exemptGroup.add(row);
+        }
+
+        const addRow = new Adw.EntryRow({title: 'Add app ID (e.g. org.gnome.Terminal)'});
+        addRow.connect('apply', () => {
+            const text = addRow.get_text().trim();
+            if (!text) return;
+            const current = settings.get_strv('exempt-apps');
+            if (!current.includes(text)) {
+                current.push(text);
+                settings.set_strv('exempt-apps', current);
+            }
+            addRow.set_text('');
+        });
+        exemptGroup.add(addRow);
+    }
+}
